// Solution
class Solution:
  def fix_nested_tags(self, s: str) -> str:
    stack = []
    result = ''
    in_tag = False
    for i in range(len(s)):
      char = s[i]
      if char === '<':
        in_tag = True
      elif char === '>':
        in_tag = False
        result += '</' + stack.pop() + '>
'
      elif in_tag:
        result += char
    return result
